import * as React from 'react';
import { Handle } from 'react-flow-renderer';
import CardContent from '@mui/material/CardContent';
import Typography from '@mui/material/Typography';
import Divider from '@mui/material/Divider';
import Box from '@mui/material/Box';
import Grid from '../vertical-divider';

const LeftContent = () => {
  return (
    <div>
      <br />
      <Box
        sx={{
          width: "90%",
          height: "flex",
          backgroundColor: "#eceff1",
          borderBottomRightRadius: "3px",
          borderTopRightRadius: "3px"
        }}>
        <Typography
          variant="body1"
          style={{
            position: "relative",
            left: "16px",
          }}>
          Response variable
        </Typography>
      </Box>
      <br />
      <Box
        sx={{
          width: "90%",
          height: "flex",
          backgroundColor: "#eceff1",
          borderBottomRightRadius: "3px",
          borderTopRightRadius: "3px"
        }}>
        <Typography
          variant="body1"
          style={{
            position: "relative",
            left: "16px",
          }}>
          Predictor variable(s)
        </Typography>
      </Box>
    </div>
  )
}

const RightContent = () => {
  return (
    <div>
      <br />
      <Box
        sx={{
          position: "relative",
          left: "16px",
          width: "90%",
          height: "flex",
          backgroundColor: "#eceff1",
          borderBottomLeftRadius: "3px",
          borderTopLeftRadius: "3px"
        }}>
        <Typography
          align="right"
          variant="body1"
          style={{
            position: "relative",
            left: "-16px",
          }}>
          Predicted response
        </Typography>
      </Box>
      <br />
      <Box
        sx={{
          position: "relative",
          left: "16px",
          width: "90%",
          height: "flex",
          backgroundColor: "#eceff1",
          borderBottomLeftRadius: "3px",
          borderTopLeftRadius: "3px"
        }}>
        <Typography
          align="right"
          variant="body1"
          style={{
            position: "relative",
            left: "-16px",
          }}>
          Residuals
        </Typography>
      </Box>
    </div>
  )
}

export default function OrdinaryLinearRegression(data) {
  return (
    <>
      <Handle
        type="target"
        position="left"
        id="a"
        style={{ top: 235,background: '#555' }}
        onConnect={(params) => console.log('handle onConnect', params)}
        isConnectable={data.data.isConnectable}
      />
      <Handle
        type="target"
        position="left"
        id="b"
        style={{ top: 303,background: '#555' }}
        onConnect={(params) => console.log('handle onConnect', params)}
        isConnectable={data.data.isConnectable}
      />

      <CardContent>
        <Typography variant="h5" component="div">
          Ordinary Linear Regression
        </Typography>
        <Typography sx={{ mb: 1.5 }} color="text.secondary">
          Linear Analaysis
        </Typography>
        <Divider />
        <div style={{
          width: "300px",
          position: 'relative',
          left: "-16px",
          paddingTop: "10px"
        }}>
          <Grid
            leftTitle="Input"
            rightTitle="Output"
            leftContent={<LeftContent />}
            rightContent={<RightContent />} />
        </div>
      </CardContent>

      <Handle
        type="source"
        position="right"
        id="a"
        style={{ top: 235, background: '#555' }}
        isConnectable={data.data.isConnectable}
      />
      <Handle
        type="source"
        position="right"
        id="b"
        style={{ top: 293, background: '#555' }}
        isConnectable={data.data.isConnectable}
      />
    </>
  )
}