import * as React from 'react';
import OrdinaryLinearRegression from './cards/ordinary-linear-regression-card'
import InputData from './cards/input-data-card'

export default function cardContent({id, type, data}) {
    switch (type){
        case "ordinary-linear-regression":
            return(<OrdinaryLinearRegression 
                    id={id}
                    data={data}/>)
        case "input-data":
            return(<InputData 
                id={id}
                data={data}/>)
    }
}