export default function newBlockGenerator(newID, type, position) {
  let newBlock = {};
  newID = newID.toString();

  switch (type) {
    case "input-data":
      newBlock = {
        id: newID,
        type: 'basicNode',
        data: {
          content: {
            type: "input-data",
            data: {
              isConnectable: true,
            }
          }
        },
        dragHandle: '.drag-handle',
        style: {},
        position: { x: 0, y: 0 }
      }
      break;
    case "ordinary-linear-regression":
      newBlock = {
        id: newID,
        type: 'basicNode',
        data: {
          content: {
            type: "ordinary-linear-regression",
            data: {
              isConnectable: true,
            }
          }
        },
        dragHandle: '.drag-handle',
        style: {},
        position: { x: 0, y: 0 }
      }
      break;

  }
  return newBlock;
}