import React from 'react'
import {useStore} from 'react-flow-renderer';

import MainCanvas from '../components/flow/main-canvas'
import MainDrawer from '../components/main-drawer'
import Box from '@mui/material/Box';
import Typography from '@mui/material/Typography'
import Dialog from '@mui/material/Dialog';

import NewBlockDialog from '../components/add-block-menu/add-block-menu';
import initialElement from '../components/flow/initial-element';
import initialPosition from '../components/flow/initial-position';
import newBlockGenerator from '../components/flow/new-block-generator';


export default function Notes() {
  const [isFirstCanvasRender, setIsFirstCanvasRender] = React.useState(true);
  const [newBlockOpen, setNewBlockOpen] = React.useState(false);
  const [elements, setElements] = React.useState([]);
  const [position, setPosition] = React.useState({}); //Track center of canvas for when making a new block

  const handleSetElements = (newElements) => {
    setElements(newElements);
    console.log("reached");
  }

  //Get block ID (not connections)
  const getBlockID = () => {
    //Filter only Blocks (we don't care about connections)
    //Block id are integer, elements are string. so filter out strings
      return elements.map(a => a.id).map( function(b) {
        return parseInt(b,10);
      }).filter(function (c) {
        return !Number.isNaN(c);
      })
  }

  //Get the max block ID
  function getMaxBlockID() {
    return Math.max.apply(null, getBlockID());
  }

  //First time start
  if (isFirstCanvasRender){
    setElements(initialElement);
    setPosition(initialPosition);
    setIsFirstCanvasRender(false);
  }
  
  //When new block is added
  const handleNewBlockClose = (selectedBlock) => {
    //Center the new block to the current view

    //concat the existing elements array with the new selected array
    setElements(
      elements.concat(
        newBlockGenerator(
          getMaxBlockID()+1,
          selectedBlock,
          
        )));
    setNewBlockOpen(false);
  }

  return (
    <>
      <MainDrawer
        newBlockOpen={setNewBlockOpen}>
        <Box
          sx={{
            width: "flex",
            height: "100%",
          }}>
          <MainCanvas 
            setElements={handleSetElements}
            elements={elements}/>
        </Box>
      </MainDrawer>
      <Dialog
        onClose={handleNewBlockClose}
        open={newBlockOpen}>
        <NewBlockDialog onClose={handleNewBlockClose} />
      </Dialog>
    </>
  )
}
