import * as React from 'react';
import PropTypes from 'prop-types';
import Button from '@mui/material/Button';
import Avatar from '@mui/material/Avatar';
import List from '@mui/material/List';
import ListItem from '@mui/material/ListItem';
import ListItemAvatar from '@mui/material/ListItemAvatar';
import ListItemText from '@mui/material/ListItemText';
import DialogTitle from '@mui/material/DialogTitle';
import DialogContent from '@mui/material/DialogContent'
import Dialog from '@mui/material/Dialog';
import PersonIcon from '@mui/icons-material/Person';
import AddIcon from '@mui/icons-material/Add';
import Typography from '@mui/material/Typography';
import Divider from '@mui/material/Divider';
import Box from '@mui/material/Box';
import Tooltip from '@mui/material/Tooltip'
import { blue } from '@mui/material/colors';

import DisabledButton from './disabled-button'
import EnabledButton from './enabled-button'

export default function NewBlocKDialog(props) {
  
  const handleValidButtonClick = (selectedBlock) => {
    props.onClose(selectedBlock);
  };

  return (
    <>
      <DialogTitle>
        Add a New Block
      </DialogTitle>
      <DialogContent dividers>
        <Typography variant="h6">Data Block</Typography>
        <Typography variant="subtitle1">Upload, import, fetch, manipulate and do so much more with data</Typography>
        <Box sx={{ '& button': { m: 1 }, paddingBottom: "10px" }}>
          <div>
            <EnabledButton onClick={() => handleValidButtonClick("input-data")}>
              Upload/Import/Fetch Data
            </EnabledButton>
            <DisabledButton>
              Split
            </DisabledButton>
            <DisabledButton>
              Filter
            </DisabledButton>
            <DisabledButton>
              Combine
            </DisabledButton>
            <DisabledButton>
              More Coming Soon!
            </DisabledButton>
          </div>
        </Box>

        <Divider />
        <Typography variant="h6">Analysis Block</Typography>
        <Typography variant="subtitle1">Analyse, model and predict with your data</Typography>
        <Box sx={{ '& button': { m: 1 }, paddingBottom: "10px" }}>
          <div>
            <EnabledButton onClick={() => handleValidButtonClick("ordinary-linear-regression")}>
              Linear Regression
            </EnabledButton>
            <EnabledButton onClick={() => handleValidButtonClick("arma")}>
              ARMA Model
            </EnabledButton>
            <EnabledButton onClick={() => handleValidButtonClick("garch")}>
              GARCH Model
            </EnabledButton>
            <EnabledButton onClick={() => handleValidButtonClick("arma-diagnostic")}>
              ARMA Diagnostic
            </EnabledButton>
            <DisabledButton>
              More Coming Soon!
            </DisabledButton>
          </div>
        </Box>

        <Divider />
        <Typography variant="h6">Logic Block</Typography>
        <Typography variant="subtitle1">Create multiple scenarios for your analysis</Typography>
        <Box sx={{ '& button': { m: 1 }, paddingBottom: "10px" }}>
          <div>
            <DisabledButton>
              If Conditional
            </DisabledButton>
            <DisabledButton>
              Cases Conditional
            </DisabledButton>
            <DisabledButton>
              More Coming Soon!
            </DisabledButton>
          </div>
        </Box>

        <Divider />
        <Typography variant="h6">Misc. Block</Typography>
        <Typography variant="subtitle1">Other miscellaneous blocks</Typography>
        <Box sx={{ '& button': { m: 1 }, paddingBottom: "10px" }}>
          <div>
            <EnabledButton onClick={() => handleValidButtonClick("misc-test")}>
              Text
            </EnabledButton>
            <EnabledButton onClick={() => handleValidButtonClick("misc-highlight-area")}>
              Highlight Area
            </EnabledButton>
            <DisabledButton>
              More Coming Soon!
            </DisabledButton>
          </div>
        </Box>

      </DialogContent>
    </>
  );
}